/* Designer polish for drawer content */
.side-tab-panel {
  padding: 30px 24px 24px;
}

.side-tab-panel .tab-panel {
  padding: 0 2px 10px 0;
}

.side-tab-panel .tab-panel h2 {
  margin: 0 0 12px;
  font-size: 17px;
  line-height: 1.15;
  letter-spacing: -0.015em;
  font-weight: 760;
  color: #f8fbff;
}

.side-tab-panel .tab-panel > p {
  margin: 0 0 20px;
  max-width: 340px;
  font-size: 14.5px;
  line-height: 1.55;
  color: #c7d5e6;
}

.side-tab-panel .stack {
  gap: 16px;
}

.side-tab-panel .settings-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 14px;
}

.side-tab-panel .field-card {
  padding: 12px 12px 14px;
  border-radius: 18px;
  background: linear-gradient(180deg, rgba(255,255,255,0.105), rgba(255,255,255,0.06));
  border: 1px solid rgba(216, 229, 244, 0.14);
  box-shadow: inset 0 1px 0 rgba(255,255,255,0.06);
  transition: border-color 0.2s ease, background 0.2s ease, box-shadow 0.2s ease;
}

.side-tab-panel .field-card:focus-within {
  border-color: rgba(125, 190, 255, 0.55);
  background: linear-gradient(180deg, rgba(255,255,255,0.13), rgba(255,255,255,0.07));
  box-shadow: 0 0 0 3px rgba(44, 144, 255, 0.14), inset 0 1px 0 rgba(255,255,255,0.08);
}

.side-tab-panel .field-card label {
  margin-bottom: 9px;
  font-size: 10.5px;
  line-height: 1.2;
  letter-spacing: 0.085em;
  font-weight: 780;
  text-transform: uppercase;
  color: #98abc1;
}

.side-tab-panel input[type="text"] {
  width: 100%;
  height: 44px;
  padding: 0 13px;
  border: 0;
  border-radius: 13px;
  background: rgba(249, 251, 253, 0.96);
  color: #152235;
  font-size: 15px;
  font-weight: 640;
  box-shadow: 0 1px 0 rgba(255,255,255,0.5), 0 10px 22px rgba(0,0,0,0.08);
}

.side-tab-panel input[type="text"]:focus {
  outline: none;
  box-shadow: 0 0 0 3px rgba(44, 144, 255, 0.24), 0 10px 22px rgba(0,0,0,0.08);
}

.side-tab-panel .actions {
  gap: 10px;
  align-items: center;
  margin-top: 2px;
}

.side-tab-panel .actions button {
  min-height: 42px;
  border-radius: 999px;
  padding: 0 16px;
  font-weight: 740;
  letter-spacing: -0.01em;
}

.side-tab-panel .btn-primary {
  background: linear-gradient(180deg, #2083df, #0964b6);
  box-shadow: 0 12px 28px rgba(0, 101, 184, 0.28);
}

.side-tab-panel .btn-secondary {
  background: rgba(255,255,255,0.92);
  color: #16304d;
  border-color: rgba(255,255,255,0.18);
  box-shadow: 0 10px 22px rgba(0,0,0,0.08);
}

.side-tab-panel .footnote {
  margin-top: 4px;
  max-width: 340px;
  font-size: 13px;
  line-height: 1.45;
  color: #adc1d7;
}

@media (max-width: 560px) {
  .side-tab-panel .settings-grid {
    grid-template-columns: 1fr;
  }
}
